INSERT INTO "product" ("id", "name", "description", "price", "sale_price", "stock_quantity", "category", "thumbnail_image", "star_rating", "seller_id") VALUES (1, 'Nokia 105 2019 Charcoal Black', 'The Nokia 105 (2019) in Charcoal Black is a simple and dependable feature phone designed for basic communication and everyday convenience. It features a compact and lightweight design with a durable polycarbonate body that helps protect it from daily wear and tear. The phone comes with a 1.77-inch display that provides a clear and easy-to-use interface for calling and texting. It also includes practical features such as dual SIM support, a built-in FM radio, a flashlight, and classic games like Snake for light entertainment. Powered by an 800mAh removable battery, the Nokia 105 (2019) offers long-lasting battery life that can stay on standby for days, making it ideal as a backup phone or for users who prefer a distraction-free mobile experience focused on essential functions.', 3999, 2999, 43, 'Electronics', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcR3DB8yNIKLtVb8wB7zv3RXKFIyaoOMgzZ5xQ&s', NULL, 1);
