INSERT INTO "product" ("id", "name", "description", "price", "sale_price", "stock_quantity", "category", "thumbnail_image", "star_rating", "seller_id") VALUES (10, 'Cetaphil Daily Advance Ultra Hydrating Lotion Dry&Sensitive Skin 473ml', 'Cetaphil Daily Advance Ultra Hydrating Lotion Dry&Sensitive Skin 473ml is a deeply hydrating lotion specially formulated for dry to very dry skin. With a unique formula, this product ensures continuous hydration for 48 hours after application. With hydrating and water-retaining ingredients like Shea Butter and Glycerin, this product is able to deeply nourish, soothe and also protect the skin from external aggressors. Moreover, the Panthenol in the formulation, not only hydrates the skin but also soothes and quickly relieves any feeling of discomfort. In addition, the presence of Niacinamide provides anti-inflammatory properties and increases ceramide synthesis, which leads to a reduction of discomfort and improvement of the skin barrier.', 1894.93, NULL, 23, 'Beauty', 'https://static.beautytocare.com/media/catalog/product/c/e/cetaphil-daily-advance-ultra-hydrating-lotion-dry-sensitive-skin-473ml_1.png', NULL, 7);
