INSERT INTO "product" ("id", "name", "description", "price", "sale_price", "stock_quantity", "category", "thumbnail_image", "star_rating", "seller_id") VALUES (12, 'N Series Agility', 'The Nerf brand levels up your game with high-performance Nerf N Series Agility dart blasters and Nerf N1 darts! You have the skills as a Nerf battler, now you have the blaster and darts to gain a superior edge in indoor and outdoor play. From the creators of the foam dart, the Nerf brand unleashes the next evolution in foam dart blasting with Nerf N Series N1 darts, delivering Extreme accuracy, speed, and distance! The Nerf N Series Agility dart blaster is built for games in which the action never stops and neither do you! Lightweight, compact, and simple to use, it''s a great blaster essential for your Nerf stockpile. The Nerf N Series Agility blaster has a rotating drum with 6-dart capacity, includes 12 Nerf N1 foam darts, and has pull back priming. To play, load darts into the drum, pull back the priming slide, and pull the trigger to fire a dart. Nerf N Series blasters are compatible only with Nerf N Series N1 darts. Eyewear recommended (not included).', 400, NULL, 7, 'Toys', 'https://rustans.com/cdn/shop/files/3262222FRONT.jpg?v=1727336460&width=800', NULL, 7);
